import React from 'react';
import Topnav from '../components/Topnav';
import Footer from '../components/Footer';
import Top_image from "../assets/top_banner.png";
import background from '../assets/background.png';
import AboutData from '../assets/About.json';

function About() {
  return (
    <>
      <Topnav />

      {/* Header Section with Background */}
      <div
        className="relative flex flex-col justify-end items-center h-96 bg-cover bg-center"
        style={{ backgroundImage: `url(${background})` }}
      >
        <div className="text-center mt-10 z-20">
          <p className="text-4xl font-bold text-white mb-2">About Me</p>
          <p className="text-2xl text-gray-200">GemAnaIyzer</p>
        </div>

        {/* Top Image */}
        <div className="absolute top-28 w-6/12 md:w-4/12">
          <img
            src={Top_image}
            alt="Gem"
            className="h-64 w-full rounded-2xl shadow-2xl border-2 border-gray-100"
          />
        </div>
      </div>

      {/* Content Section */}
      <div className="max-w-6xl mx-auto px-6 md:px-12 lg:px-20 py-16 space-y-8">
        <p className="text-gray-800 text-lg text-justify leading-relaxed">
          {AboutData.section.paragraph1}
        </p>
        <p className="text-gray-800 text-lg text-justify leading-relaxed">
          {AboutData.section.paragraph2}
        </p>
        <p className="text-gray-800 text-lg text-justify leading-relaxed">
          {AboutData.section.paragraph3}
        </p>
        <p className="text-gray-800 text-lg text-justify leading-relaxed">
          {AboutData.section.paragraph4}
        </p>
      </div>

      <Footer />
    </>
  );
}

export default About;
